/* Suggested markup: <div class="uiwiki-circular-mask-route-reveal" tabindex="0"><span>Circular Mask Route Reveal</span></div> */
.uiwiki-circular-mask-route-reveal {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-circular-mask-route-reveal > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #c5bff0;
  animation: circular_mask_route_reveal 1.8s ease-in-out infinite alternate;
}
.uiwiki-circular-mask-route-reveal:hover,
.uiwiki-circular-mask-route-reveal:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes circular_mask_route_reveal {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-circular-mask-route-reveal, .uiwiki-circular-mask-route-reveal > span { animation: none; transition: none; }
}
